  ('medical-tech-moex-17135', 'medical-tech', 'medical-tech-moex-097-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '有關脈波超音波的三種模式，下列敘述何者錯誤？', '["A模式：超音波可分析單束超音波影像，此型為單向影像", "B模式：可將A模式的音束轉換成光點，能顯示被測物的截斷面", "M模式：係利用亮點與運動時間關係，可連續觀察在運動中的運動體", "M模式的亮點移動是三度空間的線性運動，此為心臟超音波的基本原理"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:06+00:00", "source_pdf_sha1": "3b9d70c3e046", "answer_pdf_sha1": "f1c26ae8a7b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "108", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
